package com.hospital.management.controller.billing;import com.hospital.management.model.*;import com.hospital.management.util.RequestUtil;import javax.servlet.http.*;import java.time.*;import java.util.*;final class BillingRequest{private BillingRequest(){}static Long id(String v){try{long x=Long.parseLong(v);return x>0?x:null;}catch(Exception e){return null;}}static int number(String v,int d){try{return Integer.parseInt(v);}catch(Exception e){return d;}}static LocalDate date(String v){try{return v==null||v.isBlank()?null:LocalDate.parse(v);}catch(Exception e){return null;}}static AuthenticatedUser user(HttpServletRequest q){HttpSession s=q.getSession(false);Object u=s==null?null:s.getAttribute("authenticatedUser");return u instanceof AuthenticatedUser a?a:null;}static AuditContext audit(HttpServletRequest q){return RequestUtil.buildAuditContext(q);}static BillForm bill(HttpServletRequest q){BillForm f=new BillForm();f.setBillId(id(q.getParameter("billId")));f.setPatientId(id(q.getParameter("patientId")));f.setAppointmentId(id(q.getParameter("appointmentId")));f.setTaxAmount(q.getParameter("taxAmount"));f.setDiscountAmount(q.getParameter("discountAmount"));List<BillItemForm>x=new ArrayList<>();for(int i=0;i<50;i++){String p="items["+i+"]";String type=q.getParameter(p+".itemType");if(type==null)continue;BillItemForm z=new BillItemForm();z.setItemType(type);z.setDescription(q.getParameter(p+".description"));z.setQuantity(q.getParameter(p+".quantity"));z.setUnitPrice(q.getParameter(p+".unitPrice"));x.add(z);}f.setItems(x);return f;}static PaymentForm payment(HttpServletRequest q){PaymentForm f=new PaymentForm();f.setBillId(id(q.getParameter("billId")));f.setAmount(q.getParameter("amount"));f.setPaymentMethod(q.getParameter("paymentMethod"));f.setTransactionReference(q.getParameter("transactionReference"));return f;}}
